import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"ABF 載板深度研究","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/PCB研究/ABF載板深度研究.md","filePath":"Deep32Q知識庫/產業洞察/PCB研究/ABF載板深度研究.md"}'),n={name:"Deep32Q知識庫/產業洞察/PCB研究/ABF載板深度研究.md"};function r(s,t,i,g,o,f){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="abf-載板深度研究" tabindex="-1">ABF 載板深度研究 <a class="header-anchor" href="#abf-載板深度研究" aria-label="Permalink to &quot;ABF 載板深度研究&quot;">​</a></h1><p><strong>更新日期：2026-05-13</strong></p><hr><h2 id="_1-abf-載板技術介紹" tabindex="-1">1. ABF 載板技術介紹 <a class="header-anchor" href="#_1-abf-載板技術介紹" aria-label="Permalink to &quot;1. ABF 載板技術介紹&quot;">​</a></h2><h3 id="abf-vs-bt-差異" tabindex="-1">ABF vs BT 差異 <a class="header-anchor" href="#abf-vs-bt-差異" aria-label="Permalink to &quot;ABF vs BT 差異&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">ABF 載板</th><th style="text-align:left;">BT 載板</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>材料</strong></td><td style="text-align:left;">Ajinomoto Build-up Film（味之素積層膜）</td><td style="text-align:left;">Bismaleimide Triazine（苯并環丁烯樹脂）</td></tr><tr><td style="text-align:left;"><strong>應用</strong></td><td style="text-align:left;">高階 CPU/GPU/AI 加速卡</td><td style="text-align:left;">中低階 IC、網通晶片</td></tr><tr><td style="text-align:left;"><strong>層數</strong></td><td style="text-align:left;">4–12 層（高階可達 20+）</td><td style="text-align:left;">3–8 層</td></tr><tr><td style="text-align:left;"><strong>線寬/線距</strong></td><td style="text-align:left;">&lt;20μm（m-SAP 技術）</td><td style="text-align:left;">&gt;30μm</td></tr><tr><td style="text-align:left;"><strong>I/O 密度</strong></td><td style="text-align:left;">超高（&gt;2,500 pins）</td><td style="text-align:left;">中低</td></tr><tr><td style="text-align:left;"><strong>單價</strong></td><td style="text-align:left;">高（AI GPU 載板 $500–2,000+/片）</td><td style="text-align:left;">低（$50–300/片）</td></tr><tr><td style="text-align:left;"><strong>主要供應商</strong></td><td style="text-align:left;">Ibiden、欣興、南電、景碩、AT&amp;S</td><td style="text-align:left;">景碩、三星電機、Shinko</td></tr></tbody></table><h3 id="為什麼-abf-是-ai-加速卡-cpu-gpu-的關鍵材料" tabindex="-1">為什麼 ABF 是 AI 加速卡/CPU/GPU 的關鍵材料？ <a class="header-anchor" href="#為什麼-abf-是-ai-加速卡-cpu-gpu-的關鍵材料" aria-label="Permalink to &quot;為什麼 ABF 是 AI 加速卡/CPU/GPU 的關鍵材料？&quot;">​</a></h3><ol><li><strong>超高 I/O 密度</strong>：AI GPU（如 NVIDIA B200）I/O 數超過 10,000 個，ABF 可支援 &gt;2,500 pins/in²</li><li><strong>極致散熱</strong>：ABF 膜熱膨脹係數（CTE）與矽晶片接近，降低熱應力</li><li><strong>訊號完整性</strong>：低介電常數（Dk）和低損耗因子（Df），適合高速傳輸</li><li><strong>翹曲控制</strong>：大尺寸 AI 載板（&gt;150×150mm）的翹曲控制是技術難點</li></ol><h3 id="技術難點" tabindex="-1">技術難點 <a class="header-anchor" href="#技術難點" aria-label="Permalink to &quot;技術難點&quot;">​</a></h3><ul><li><strong>極高精度佈線</strong>：m-SAP（半加成法）線寬/線距 &lt;20μm</li><li><strong>翹曲控制</strong>：大尺寸載板（&gt;150mm 邊長）的翹曲 &lt;0.75%</li><li><strong>高密度佈線</strong>：BGA 焊點間距 &lt;0.4mm</li><li><strong>層數對準精度</strong>：&gt;12 層的層間對準誤差 &lt;5μm</li></ul><hr><h2 id="_2-全球市場規模" tabindex="-1">2. 全球市場規模 <a class="header-anchor" href="#_2-全球市場規模" aria-label="Permalink to &quot;2. 全球市場規模&quot;">​</a></h2><h3 id="abf-載板市場數據-2025–2032" tabindex="-1">ABF 載板市場數據（2025–2032） <a class="header-anchor" href="#abf-載板市場數據-2025–2032" aria-label="Permalink to &quot;ABF 載板市場數據（2025–2032）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:left;">數值</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">2024 全球 ABF 載板市場</td><td style="text-align:left;">~US$4.89B</td><td style="text-align:left;">360iResearch / MarketGrowthReports</td></tr><tr><td style="text-align:left;">2025 全球 ABF 載板市場</td><td style="text-align:left;">~US$5.42–11.1B（不同預測）</td><td style="text-align:left;">多個研究機構</td></tr><tr><td style="text-align:left;">2032 全球 ABF 載板市場預估</td><td style="text-align:left;">~US$9.55–13.3B</td><td style="text-align:left;">CAGR 10.6% (2024-2032)</td></tr><tr><td style="text-align:left;">AI 驅動 ABF 載板成長率</td><td style="text-align:left;">&gt;15% CAGR（2025-2030）</td><td style="text-align:left;">產業分析</td></tr></tbody></table><h3 id="全球-abf-載板供應商市佔率-2024" tabindex="-1">全球 ABF 載板供應商市佔率（2024） <a class="header-anchor" href="#全球-abf-載板供應商市佔率-2024" aria-label="Permalink to &quot;全球 ABF 載板供應商市佔率（2024）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">排名</th><th style="text-align:left;">公司</th><th style="text-align:left;">國家</th><th style="text-align:left;">市佔率</th><th style="text-align:left;">AI 相關產品</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:left;"><strong>Unimicron（欣興）</strong></td><td style="text-align:left;">🇹🇼</td><td style="text-align:left;">~22%</td><td style="text-align:left;">AI 加速卡 ABF 載板（NVIDIA 認證）</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;"><strong>Ibiden</strong></td><td style="text-align:left;">🇯🇵</td><td style="text-align:left;">~20%</td><td style="text-align:left;">全球載板龍頭，AI GPU/CPU</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:left;"><strong>AT&amp;S</strong></td><td style="text-align:left;">🇦🇹</td><td style="text-align:left;">~15%</td><td style="text-align:left;">歐洲唯一，AI 伺服器載板</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:left;"><strong>Nan Ya PCB（南電）</strong></td><td style="text-align:left;">🇹🇼</td><td style="text-align:left;">~12%</td><td style="text-align:left;">ABF 載板佔營收 &gt;65%</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:left;"><strong>Shinko Electric</strong></td><td style="text-align:left;">🇯🇵</td><td style="text-align:left;">~10%</td><td style="text-align:left;">封裝載板，AI 相關產品</td></tr><tr><td style="text-align:left;">6</td><td style="text-align:left;"><strong>Kinsus（景碩）</strong></td><td style="text-align:left;">🇹🇼</td><td style="text-align:left;">~8%</td><td style="text-align:left;">ABF+BT 雙產品線</td></tr><tr><td style="text-align:left;">其他</td><td style="text-align:left;">三星電機、Kyocera 等</td><td style="text-align:left;">多國</td><td style="text-align:left;">~13%</td><td style="text-align:left;">部分 AI 產品</td></tr></tbody></table><blockquote><p><strong>台廠三雄（欣興+南電+景碩）合計市佔約 42%</strong>，是全球 ABF 載板最重要的供應商集群。</p></blockquote><hr><h2 id="_3-台廠三雄深度分析" tabindex="-1">3. 台廠三雄深度分析 <a class="header-anchor" href="#_3-台廠三雄深度分析" aria-label="Permalink to &quot;3. 台廠三雄深度分析&quot;">​</a></h2><h3 id="🔥-欣興-3037-—-台灣-abf-載板龍頭" tabindex="-1">🔥 欣興 (3037) — 台灣 ABF 載板龍頭 <a class="header-anchor" href="#🔥-欣興-3037-—-台灣-abf-載板龍頭" aria-label="Permalink to &quot;🔥 欣興 (3037) — 台灣 ABF 載板龍頭&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全球市佔率</strong></td><td style="text-align:left;">~22%（全球第一）</td></tr><tr><td style="text-align:left;"><strong>AI 相關產品</strong></td><td style="text-align:left;">AI 加速卡 ABF 載板（NVIDIA 認證）</td></tr><tr><td style="text-align:left;"><strong>2026 Q1 營收</strong></td><td style="text-align:left;">NT$37.45B（+24.4% YoY）</td></tr><tr><td style="text-align:left;"><strong>2026 資本支出</strong></td><td style="text-align:left;">NT$34B（+20% YoY，創新高）</td></tr><tr><td style="text-align:left;"><strong>擴產重點</strong></td><td style="text-align:left;">光復廠 + 新竹新廠，高階 ABF 載板產能</td></tr><tr><td style="text-align:left;"><strong>技術路線</strong></td><td style="text-align:left;">m-SAP 量產，AI GPU 載板良率持續提升</td></tr><tr><td style="text-align:left;"><strong>客戶</strong></td><td style="text-align:left;">NVIDIA、AMD、Intel、高通等 AI 晶片大廠</td></tr><tr><td style="text-align:left;"><strong>2026 亮點</strong></td><td style="text-align:left;">資本支出創新高，AI 載板產能持續擴充</td></tr></tbody></table><p><strong>來源：digitimes (2026/02), SimplyWallSt (2026/04)</strong></p><h3 id="南電-8046-—-abf-載板佔比最高" tabindex="-1">南電 (8046) — ABF 載板佔比最高 <a class="header-anchor" href="#南電-8046-—-abf-載板佔比最高" aria-label="Permalink to &quot;南電 (8046) — ABF 載板佔比最高&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>ABF 載板佔營收</strong></td><td style="text-align:left;">&gt;65%（台廠中最高）</td></tr><tr><td style="text-align:left;"><strong>集團背景</strong></td><td style="text-align:left;">台塑集團旗下，客戶群分散（非單一依賴）</td></tr><tr><td style="text-align:left;"><strong>技術路線</strong></td><td style="text-align:left;">m-SAP 量產進度持續推進中</td></tr><tr><td style="text-align:left;"><strong>產品組合</strong></td><td style="text-align:left;">ABF + BT 雙產品線，分散風險</td></tr><tr><td style="text-align:left;"><strong>2026 展望</strong></td><td style="text-align:left;">AI 驅動供需轉緊，載板價格上漲空間大</td></tr><tr><td style="text-align:left;"><strong>擴產計畫</strong></td><td style="text-align:left;">配合 AI 需求持續投資高階載板產能</td></tr></tbody></table><h3 id="景碩-3189-—-abf-bt-雙產品線" tabindex="-1">景碩 (3189) — ABF+BT 雙產品線 <a class="header-anchor" href="#景碩-3189-—-abf-bt-雙產品線" aria-label="Permalink to &quot;景碩 (3189) — ABF+BT 雙產品線&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>產品組合</strong></td><td style="text-align:left;">ABF + BT 雙產品線，AI+車用多元布局</td></tr><tr><td style="text-align:left;"><strong>財務狀況</strong></td><td style="text-align:left;">已審計完成（財務+經營分析）</td></tr><tr><td style="text-align:left;"><strong>2026 展望</strong></td><td style="text-align:left;">ABF 載板供需轉緊，BT 載板穩定貢獻</td></tr><tr><td style="text-align:left;"><strong>客戶認證</strong></td><td style="text-align:left;">持續拓展 AI 加速卡客戶認證</td></tr><tr><td style="text-align:left;"><strong>擴產計畫</strong></td><td style="text-align:left;">配合市場需求調整 ABF/BT 產能比例</td></tr></tbody></table><hr><h2 id="_4-供需周期分析" tabindex="-1">4. 供需周期分析 <a class="header-anchor" href="#_4-供需周期分析" aria-label="Permalink to &quot;4. 供需周期分析&quot;">​</a></h2><h3 id="abf-載板供需週期-2023–2028" tabindex="-1">ABF 載板供需週期（2023–2028） <a class="header-anchor" href="#abf-載板供需週期-2023–2028" aria-label="Permalink to &quot;ABF 載板供需週期（2023–2028）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">期間</th><th style="text-align:left;">供需狀態</th><th style="text-align:left;">價格趨勢</th><th style="text-align:left;">關鍵事件</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>2023–2024</strong></td><td style="text-align:left;">供過於求（消費性電子疲弱）</td><td style="text-align:left;">價格下跌 10–20%</td><td style="text-align:left;">AI 需求尚未爆發，產能過剩</td></tr><tr><td style="text-align:left;"><strong>2025 H1</strong></td><td style="text-align:left;">供需接近平衡</td><td style="text-align:left;">價格持平或微跌</td><td style="text-align:left;">AI 需求開始顯現，消費性電子復甦</td></tr><tr><td style="text-align:left;"><strong>2025 H2–2026</strong></td><td style="text-align:left;">供需轉緊</td><td style="text-align:left;">ABF 膜價格 +30%，載板 +5–10%</td><td style="text-align:left;">AI GPU/CPU 需求爆發，產能不足</td></tr><tr><td style="text-align:left;"><strong>2027–2028</strong></td><td style="text-align:left;">新產能開出，供需再平衡</td><td style="text-align:left;">價格回穩</td><td style="text-align:left;">台廠擴產完成，玻璃基板開始挑戰</td></tr></tbody></table><h3 id="關鍵觀察點" tabindex="-1">關鍵觀察點 <a class="header-anchor" href="#關鍵觀察點" aria-label="Permalink to &quot;關鍵觀察點&quot;">​</a></h3><ul><li><strong>ABF 膜壟斷</strong>：味之素（日）全球唯一供應商，2026 年預估漲價 ~30%</li><li><strong>台廠擴產</strong>：欣興 NT$34B + 南電 + 景碩，2026–2027 年產能大幅擴充</li><li><strong>玻璃基板威脅</strong>：Intel/Samsung 2026 年開始量產，長期可能取代 ABF（高階 AI 領域）</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>360iResearch / MarketGrowthReports</strong> (2025): ABF 載板市場 US$4.89B (2024) → US$9.55B (2032), CAGR 10.6%</li><li><strong>digitimes</strong> (2026/02): 欣興 2026 Q1 營收 NT$37.45B, 資本支出 NT$34B</li><li><strong>SimplyWallSt</strong> (2026/04): 欣興營收年增率預估 +21.2%/年</li><li><strong>CTEE</strong> (2026/05): 台光電 AI CCL 市佔 ~33%, NVIDIA H100 OAM/UBB &gt;80%</li><li><strong>Prismark</strong> (2025): IC 載板 CAGR ~7% (2023-2028)</li><li><strong>wccftech.com</strong> (2026): ABF 膜漲價至 2027 年，載板 +5–10%</li></ol>',35)])])}const h=e(n,[["render",r]]);export{y as __pageData,h as default};
